from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core

class PrismGetAssetsNode(BaseNode):
    name = "Prism: Get Assets"
    category = "DCCs"

    def __init__(self):
        super().__init__(use_exec=False)
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_output("assets", "list")
        self.add_output("count", "int")

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        if core is None:
            self.log_error("No PrismCore provided.")
            return {'assets': [], 'count': 0}
        try:
            assets = core.entities.getAssets() or []
            self.log_info(f"Found {len(assets)} asset(s).")
            return {'assets': list(assets), 'count': len(assets)}
        except Exception as e:
            self.log_error(f"getAssets failed: {e}")
            return {'assets': [], 'count': 0}

def register_node():
    return PrismGetAssetsNode
